'use client';

import React from 'react';
import { Plus, Settings2, Zap, Layout, Copy, Trash2 } from 'lucide-react';

interface ManifestItem {
  id: string;
  label?: string;
  bind?: string;
  presentation?: {
    tab?: string;
    [key: string]: any;
  };
}

interface ControlRegistryProps {
  manifest: {
    ui?: {
      controls?: ManifestItem[];
      jacks?: ManifestItem[];
    };
  };
  selectedItemId: string | null;
  onSelectItem: (id: string) => void;
  onAddEntity: (type: 'control' | 'jack') => void;
  onDuplicateItem: (id: string) => void;
  onRemoveItem: (id: string) => void;
}

export default function ControlRegistry({ 
  manifest, 
  selectedItemId, 
  onSelectItem, 
  onAddEntity, 
  onDuplicateItem,
  onRemoveItem 
}: ControlRegistryProps) {
  const controls = manifest?.ui?.controls || [];
  const jacks = manifest?.ui?.jacks || [];

  const renderList = (items: ManifestItem[], title: string, type: 'control' | 'jack', Icon: React.ComponentType<any>) => (
    <div className="space-y-3">
      <div className="flex justify-between items-center bg-white/5 p-2 rounded-xs border border-outline/10">
        <div className="flex items-center gap-2">
          <Icon className="w-3 h-3 text-primary/60" />
          <span className="text-[9px] font-black uppercase tracking-widest text-foreground/40">{title}</span>
        </div>
        <button 
          onClick={() => onAddEntity(type)}
          className="p-1 hover:bg-primary hover:text-black rounded-xs transition-all text-primary/60"
        >
          <Plus className="w-3 h-3" />
        </button>
      </div>

      <div className="space-y-1">
        {items.map((item) => (
          <div 
            key={item.id}
            onClick={() => onSelectItem(item.id)}
            className={`group relative flex items-center justify-between p-2 rounded-xs border transition-all cursor-pointer ${
              selectedItemId === item.id 
                ? 'bg-primary/20 border-primary/40 text-primary shadow-[0_0_10px_rgba(0,240,255,0.1)]' 
                : 'bg-black/20 border-outline/10 text-foreground/40 hover:border-outline/40 hover:bg-white/5'
            }`}
          >
            <div className="flex items-center gap-2 overflow-hidden">
              <div className={`w-1 h-3 rounded-full ${selectedItemId === item.id ? 'bg-primary' : 'bg-outline/20'}`} />
              <div className="flex flex-col truncate">
                <span className="text-[10px] font-bold truncate tracking-tight">{item.label || item.id}</span>
                <span className="text-[7px] font-mono opacity-40 uppercase truncate">{item.id}</span>
              </div>
            </div>

            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
              <button 
                onClick={(e) => { e.stopPropagation(); onDuplicateItem(item.id); }}
                className="p-1 hover:bg-white/10 rounded-xs text-foreground/20 hover:text-primary transition-colors"
                title="Duplicate Entity"
              >
                <Copy className="w-2.5 h-2.5" />
              </button>
              <button 
                onClick={(e) => { e.stopPropagation(); onRemoveItem(item.id); }}
                className="p-1 hover:bg-red-500/10 rounded-xs text-foreground/20 hover:text-red-400 transition-colors"
                title="Remove Entity"
              >
                <Trash2 className="w-2.5 h-2.5" />
              </button>
            </div>
          </div>
        ))}
        {items.length === 0 && (
          <div className="py-6 border border-dashed border-outline/10 rounded-xs flex flex-col items-center justify-center gap-2 opacity-20">
             <Layout className="w-4 h-4" />
             <span className="text-[7px] font-black uppercase tracking-widest">No {title}</span>
          </div>
        )}
      </div>
    </div>
  );

  return (
    <div className="space-y-8">
      {renderList(controls, 'Interactive Controls', 'control', Settings2)}
      {renderList(jacks, 'Signal Ports / Jacks', 'jack', Zap)}
    </div>
  );
}

'use client';

import React, { useMemo } from 'react';
import { Zap, Database, Palette, CheckCircle, AlertTriangle } from 'lucide-react';

interface UIElement {
  bind?: string;
  presentation?: {
    attachments?: any[];
  };
}

interface ModuleHubProps {
  manifest: {
    ui?: {
      controls?: UIElement[];
      jacks?: UIElement[];
    };
    metadata?: {
      name?: string;
      family?: string;
      description?: string;
      status?: string;
      rack?: { hp?: number };
    };
    resources?: { wasm?: string };
    schemaVersion?: string;
  };
  contract: {
    id: string;
    parameters?: any[];
    ports?: any[];
  } | null;
  triggerUpload: (type: string) => void;
}

export default function ModuleHub({ manifest, contract, triggerUpload }: ModuleHubProps) {

  // INDUSTRIAL HEALTH ANALYTICS
  const metrics = useMemo(() => {
    const controls = manifest.ui?.controls || [];
    const jacks = manifest.ui?.jacks || [];
    const allItems = [...controls, ...jacks];

    // 1. Binding Coverage
    const boundCount = allItems.filter(i => i.bind && i.bind !== '').length;
    const bindCoverage = allItems.length > 0 ? (boundCount / allItems.length) * 100 : 0;

    // 2. Metadata Audit
    const meta = manifest.metadata || {};
    const metaFields = [meta.name, meta.family, meta.description, meta.status];
    const metaScore = (metaFields.filter(f => !!f).length / metaFields.length) * 100;

    // 3. UI Density (Optimal 60-80%)
    const hp = meta.rack?.hp || 12;
    const density = Math.min(100, (allItems.length / (hp * 0.8)) * 100);

    // 4. Attachment Depth
    const itemsWithAtt = allItems.filter(i => (i.presentation?.attachments?.length || 0) > 0).length;
    const attScore = allItems.length > 0 ? (itemsWithAtt / allItems.length) * 100 : 0;

    // 5. Overall System Readiness
    const overall = (bindCoverage + metaScore + (100 - Math.abs(70 - density)) + attScore) / 4;

    return [
      { label: 'BND', value: bindCoverage, color: 'bg-primary' },
      { label: 'MET', value: metaScore, color: 'bg-accent' },
      { label: 'DEN', value: density, color: 'bg-blue-400' },
      { label: 'ATT', value: attScore, color: 'bg-purple-400' },
      { label: 'SYS', value: overall, color: 'bg-green-400' }
    ];
  }, [manifest]);

  const sysReady = metrics[4].value > 80;

  return (
    <div className="flex flex-col gap-8 h-full overflow-y-auto custom-scrollbar pr-2">
      {/* LOGIC ASSETS */}
      <div className="space-y-3">
        <div className="text-[9px] font-black text-foreground/40 uppercase tracking-widest flex justify-between items-center">
          <span>Logic Assets</span>
          {contract ? (
            <div className="flex items-center gap-1 text-green-400">
               <CheckCircle className="w-2.5 h-2.5" />
               <span className="text-[7px]">SYS_READY</span>
            </div>
          ) : (
            <div className="flex items-center gap-1 text-amber-500">
               <AlertTriangle className="w-2.5 h-2.5" />
               <span className="text-[7px]">MISSING_CONTRACT</span>
            </div>
          )}
        </div>
        <div className="grid grid-cols-3 gap-2">
          <button onClick={() => triggerUpload('wasm-upload')} className="flex flex-col items-center justify-center gap-1.5 p-3 bg-black/40 border border-outline rounded-sm hover:border-primary/40 hover:bg-primary/5 transition-all group relative overflow-hidden">
            <Zap className="w-3 h-3 text-primary group-hover:scale-125 transition-transform" />
            <span className="text-[7px] font-bold uppercase tracking-tighter text-foreground/40">WASM</span>
            {manifest.resources?.wasm && <div className="absolute top-0 right-0 w-1 h-full bg-primary/20" />}
          </button>
          <button onClick={() => triggerUpload('contract-upload')} className="flex flex-col items-center justify-center gap-1.5 p-3 bg-black/40 border border-outline rounded-sm hover:border-accent/40 hover:bg-accent/5 transition-all group relative overflow-hidden">
            <Database className="w-3 h-3 text-accent group-hover:scale-125 transition-transform" />
            <span className="text-[7px] font-bold uppercase tracking-tighter text-foreground/40">ABI</span>
            {contract && <div className="absolute top-0 right-0 w-1 h-full bg-accent/20" />}
          </button>
          <button onClick={() => triggerUpload('manifest-upload')} className="flex flex-col items-center justify-center gap-1.5 p-3 bg-black/40 border border-outline rounded-sm hover:border-cyan-400/40 hover:bg-cyan-400/5 transition-all group relative overflow-hidden">
            <Palette className="w-3 h-3 text-cyan-400 group-hover:scale-125 transition-transform" />
            <span className="text-[7px] font-bold uppercase tracking-tighter text-foreground/40">JSON</span>
            {manifest.schemaVersion && <div className="absolute top-0 right-0 w-1 h-full bg-cyan-400/20" />}
          </button>
        </div>

        {contract && (
          <div className="p-2.5 bg-black/20 border border-outline/10 rounded-sm space-y-2">
            <div className="flex justify-between items-center">
              <span className="text-[7px] text-foreground/30 font-bold uppercase">Target ID</span>
              <span className="text-[8px] text-primary font-mono font-black">{contract.id}</span>
            </div>
            <div className="h-[1px] bg-outline/5 w-full" />
            <div className="flex justify-between items-center">
              <span className="text-[7px] text-foreground/30 font-bold uppercase">ABI Ports</span>
              <span className="text-[8px] text-foreground/60 font-black">{contract.parameters?.length || 0}P / {contract.ports?.length || 0}S</span>
            </div>
          </div>
        )}
      </div>

      {/* INDUSTRIAL STATUS ANALYZER */}
      <div className="mt-auto p-4 bg-black/40 border border-outline/20 rounded-sm space-y-4">
         <div className="flex items-center justify-between">
            <p className="text-[8px] font-black text-foreground/60 uppercase tracking-widest">Industrial Status</p>
            <div className={`px-1.5 py-0.5 rounded-[2px] text-[6px] font-black uppercase ${sysReady ? 'bg-green-500/20 text-green-400' : 'bg-amber-500/20 text-amber-400'}`}>
               {sysReady ? 'Stable' : 'Incomplete'}
            </div>
         </div>

         <div className="flex justify-between items-end h-12 gap-2 px-1">
            {metrics.map((m, i) => (
              <div key={i} className="flex-1 flex flex-col items-center gap-1.5">
                <div className="w-full bg-white/5 rounded-t-[1px] relative overflow-hidden h-10">
                   <div 
                      className={`absolute bottom-0 left-0 w-full transition-all duration-700 ease-out ${m.color}`} 
                      style={{ height: `${m.value}%` }} 
                   />
                </div>
                <span className="text-[6px] font-bold text-foreground/30">{m.label}</span>
              </div>
            ))}
         </div>

         <div className="grid grid-cols-2 gap-2 pt-2 border-t border-outline/5">
            <div className="flex flex-col">
               <span className="text-[6px] text-foreground/30 uppercase font-black">Ready Score</span>
               <span className={`text-[10px] font-black font-mono ${sysReady ? 'text-green-400' : 'text-amber-400'}`}>
                  {Math.round(metrics[4].value)}%
               </span>
            </div>
            <div className="flex flex-col text-right">
               <span className="text-[6px] text-foreground/30 uppercase font-black">Audit Mode</span>
               <span className="text-[10px] font-black font-mono text-primary">ERA 7.1</span>
            </div>
         </div>
      </div>
    </div>
  );
}

'use client';

import { motion, AnimatePresence } from 'framer-motion';

interface NodeCanvasItem {
  id: string;
  label?: string;
  bind?: string;
  type?: string;
  presentation?: {
    attachments?: any[];
  };
}

interface NodeCanvasProps {
  manifest: {
    id?: string;
    schemaVersion?: string;
    ui?: {
      controls?: NodeCanvasItem[];
      jacks?: NodeCanvasItem[];
    };
    registry?: NodeCanvasItem[];
  };
  contract: {
    omega_version?: string;
    parameters?: { id: string }[];
    ports?: { id: string }[];
  } | null;
  selectedItemId: string | null;
  onSelectItem: (id: string) => void;
}

export default function NodeCanvas({ manifest, contract, selectedItemId, onSelectItem }: NodeCanvasProps) {
  const isV7 = manifest?.schemaVersion?.startsWith('7') || manifest?.schemaVersion === '7.0';

  // Combine all items for visualization
  const items = isV7 
    ? [...(manifest?.ui?.controls || []), ...(manifest?.ui?.jacks || [])]
    : (manifest?.registry || []);

  return (
    <div className="w-full h-full relative flex items-center justify-center overflow-hidden">
      {/* BACKGROUND GRID */}
      <div 
        className="absolute inset-0 opacity-[0.03]" 
        style={{ 
          backgroundImage: 'radial-gradient(circle, #00f0ff 1px, transparent 1px)', 
          backgroundSize: '40px 40px' 
        }} 
      />

      <div className="relative flex items-center justify-center">
        {/* CENTER NODE (WASM/MODULE) */}
        <motion.div 
          layoutId="center-node"
          initial={{ opacity: 0, scale: 0 }}
          animate={{ opacity: 1, scale: 1 }}
          className="relative z-20 w-32 h-32 rounded-full border-2 border-primary/40 flex flex-col items-center justify-center bg-black/80 cyan-bloom shadow-[0_0_30px_rgba(0,240,255,0.1)]"
        >
          <div className="text-[8px] font-bold text-primary/50 uppercase tracking-[0.2em] mb-1">Module ID</div>
          <div className="text-sm font-headline font-bold text-primary italic uppercase tracking-tighter truncate max-w-[100px]">
            {manifest?.id || '???'}
          </div>

          {contract && (
             <motion.div 
               initial={{ opacity: 0, y: 5 }}
               animate={{ opacity: 1, y: 0 }}
               className="mt-2 text-[7px] bg-green-500/20 text-green-400 px-2 py-0.5 rounded-full border border-green-500/30 uppercase font-bold"
             >
               Contract v{contract.omega_version || '7.0'}
             </motion.div>
          )}
        </motion.div>

        {/* PARAMETERS NODES (ORBITAL) */}
        <AnimatePresence>
          {items.map((item: NodeCanvasItem, index: number) => {
            const angle = (index / items.length) * (2 * Math.PI);
            const radius = 180;
            const x = Math.cos(angle) * radius;
            const y = Math.sin(angle) * radius;

            // Mapping Check (Case-Insensitive)
            const bindId = (isV7 ? item.bind : item.id)?.toLowerCase();
            const isJack = isV7 && manifest?.ui?.jacks?.some((j: NodeCanvasItem) => j.id === item.id);

            const inContract = isJack
              ? contract?.ports?.some((p: { id: string }) => p.id.toLowerCase() === bindId)
              : contract?.parameters?.some((p: { id: string }) => p.id.toLowerCase() === bindId);

            return (
              <motion.div
                key={item.id}
                initial={{ opacity: 0, x: 0, y: 0 }}
                animate={{ opacity: 1, x, y }}
                exit={{ opacity: 0, scale: 0 }}
                className="absolute z-10 group"
                onClick={() => onSelectItem(item.id)}
              >
                {/* Connection Line */}
                <svg className="absolute top-1/2 left-1/2 overflow-visible pointer-events-none" style={{ width: 0, height: 0 }}>
                   <motion.line 
                     initial={{ pathLength: 0 }}
                     animate={{ pathLength: 1 }}
                     x1={0} y1={0} x2={-x} y2={-y} 
                     stroke="currentColor" 
                     className={`${inContract || !contract ? (isJack ? 'text-accent/20' : 'text-primary/20') : 'text-red-500/20'} stroke-[1px]`}
                     strokeDasharray="4 4"
                   />
                </svg>

                <div className={`
                  w-10 h-10 rounded-sm border transform -translate-x-1/2 -translate-y-1/2 
                  flex items-center justify-center transition-all duration-300 cursor-pointer
                  ${selectedItemId === item.id ? (isJack ? 'scale-110 border-accent ring-2 ring-accent/20 bg-accent/20' : 'scale-110 border-primary ring-2 ring-primary/20 bg-primary/20') : (isJack ? 'bg-black/60 border-accent/30 hover:border-accent hover:orange-bloom' : 'bg-black/60 border-primary/30 hover:border-primary hover:cyan-bloom')}
                `}>
                  <span className={`text-[8px] font-bold uppercase tracking-tighter text-center px-1 ${inContract || !contract ? (isJack ? 'text-accent/70' : 'text-primary/70') : 'text-red-400'}`}>
                    {(item.label || item.id).substring(0, 4)}
                  </span>

                  {/* Tooltip on hover */}
                  <div className="absolute top-12 left-1/2 -translate-x-1/2 whitespace-nowrap bg-surface border border-outline p-2 rounded-sm opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none z-50 shadow-xl">
                     <div className="text-[9px] font-bold text-foreground uppercase">{item.label || item.id}</div>
                     <div className="text-[7px] text-foreground/40 mt-1 uppercase">
                       {isV7 ? `Bind: ${item.bind}` : `Type: ${item.type}`}
                     </div>
                     {!inContract && contract && (
                       <div className="text-[7px] text-red-400 mt-1 font-bold">MISSING IN CONTRACT</div>
                     )}
                  </div>
                </div>
              </motion.div>
            );
          })}
        </AnimatePresence>

        {/* ORBITAL RINGS */}
        <div className="absolute inset-[-180px] rounded-full border border-outline/5 pointer-events-none" />
        <motion.div 
          animate={{ rotate: 360 }}
          transition={{ duration: 60, repeat: Infinity, ease: 'linear' }}
          className="absolute inset-[-185px] rounded-full border border-primary/5 border-dashed pointer-events-none"
        />
      </div>

      <div className="absolute bottom-8 left-8 text-[9px] font-mono text-primary/30 uppercase tracking-widest leading-relaxed">
        Engine: OMEGA v7.0<br />
        Mode: Orbital Hub<br />
        Status: {items.length} Elements Online
      </div>
    </div>
  );
}

