'use client';

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Fingerprint, Settings, Palette, Paperclip, Shield, Package } from 'lucide-react';
import IdentitySection from './inspector/IdentitySection';
import LogicSection from './inspector/LogicSection';
import AestheticSection from './inspector/AestheticSection';
import AttachmentsSection from './inspector/AttachmentsSection';
import EngineeringSection from './inspector/EngineeringSection';
import CellPreview from './inspector/CellPreview';

interface ManifestEntity {
  id: string;
  label?: string;
  metadata?: any;
  presentation?: {
    component?: string;
    attachments?: any[];
    [key: string]: any;
  };
  [key: string]: any;
}

interface PropertyPanelProps {
  item: ManifestEntity;
  onUpdate: (updates: Partial<ManifestEntity>) => void;
  onClose: () => void;
  availableBinds?: string[];
  scale?: number;
}

export default function PropertyPanel({ item, onUpdate, onClose, availableBinds = [], scale = 1 }: PropertyPanelProps) {
  const [activeSection, setActiveSection] = React.useState<string>('identity');

  // Detect if we are editing the module itself or a specific control/jack
  const isModule = !!item.metadata;

  const sections = React.useMemo(() => (
    isModule ? [
      { id: 'identity', label: 'Identity', icon: Fingerprint, color: 'text-primary' },
    ] : [
      { id: 'identity', label: 'Identity', icon: Fingerprint, color: 'text-primary' },
      { id: 'engineering', label: 'Engineering', icon: Shield, color: 'text-accent' },
      { id: 'logic', label: 'Logic', icon: Settings, color: 'text-blue-400' },
      { id: 'aesthetic', label: 'Aesthetic', icon: Palette, color: 'text-purple-400' },
      { id: 'attachments', label: 'Attachments', icon: Paperclip, color: 'text-green-400' },
    ]
  ), [isModule]);

  // Auto-reset tab if current one disappears
  React.useEffect(() => {
    if (!sections.find(s => s.id === activeSection)) {
      setActiveSection('identity');
    }
  }, [isModule, sections, activeSection]);

  const handleFieldUpdate = (fieldUpdates: Partial<ManifestEntity>) => {
    onUpdate({ ...item, ...fieldUpdates });
  };

  return (
    <div className="h-full bg-[#0a0a0a] border-l border-outline flex flex-col shadow-2xl overflow-hidden">
      {/* HEADER */}
      <header className="p-4 border-b border-outline/20 bg-black/40 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-xs bg-primary/10 border border-primary/20 flex items-center justify-center">
             {isModule ? <Package className="w-4 h-4 text-primary" /> : <Settings className="w-4 h-4 text-primary" />}
          </div>
          <div>
            <h2 className="text-[10px] font-black uppercase tracking-widest text-foreground/80">
              {isModule ? 'Module Configuration' : 'Entity Inspector'}
            </h2>
            <p className="text-[8px] font-mono text-foreground/30 truncate max-w-[200px]">{item.id}</p>
          </div>
        </div>
        {!isModule && (
          <button 
            onClick={onClose}
            className="p-1.5 hover:bg-white/5 rounded-xs text-foreground/40 hover:text-foreground transition-all"
          >
            <X className="w-4 h-4" />
          </button>
        )}
      </header>

      {/* CELL PREVIEW (Only for items) */}
      {!isModule && <CellPreview item={item} />}

      {/* NAVIGATION TABS */}
      <nav className="flex border-b border-outline/10 bg-black/20 p-1 shrink-0">
        {sections.map((section) => (
          <button
            key={section.id}
            onClick={() => setActiveSection(section.id)}
            className={`flex-1 py-2 flex flex-col items-center gap-1 rounded-xs transition-all ${
              activeSection === section.id 
                ? 'bg-white/5 text-foreground' 
                : 'text-foreground/30 hover:text-foreground/60 hover:bg-white/2'
            }`}
          >
            <section.icon className={`w-3.5 h-3.5 ${activeSection === section.id ? section.color : ''}`} />
            <span className="text-[7px] font-black uppercase tracking-tighter">{section.label}</span>
          </button>
        ))}
      </nav>

      {/* CONTENT AREA */}
      <div className="flex-1 overflow-y-auto custom-scrollbar p-6">
        <AnimatePresence mode="wait">
          <motion.div
            key={activeSection}
            initial={{ opacity: 0, x: 10 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -10 }}
            transition={{ duration: 0.15 }}
          >
            {activeSection === 'identity' && (
              <IdentitySection item={item} onUpdate={handleFieldUpdate} />
            )}

            {!isModule && (
              <>
                {activeSection === 'engineering' && (
                  <EngineeringSection item={item} onUpdate={handleFieldUpdate} />
                )}

                {activeSection === 'logic' && (
                  <LogicSection item={item} onUpdate={handleFieldUpdate} />
                )}

                {activeSection === 'aesthetic' && (
                  <AestheticSection item={item} onUpdate={handleFieldUpdate} />
                )}

                {activeSection === 'attachments' && (
                  <AttachmentsSection 
                    item={item} 
                    onUpdate={handleFieldUpdate} 
                    availableBinds={availableBinds}
                  />
                )}
              </>
            )}
          </motion.div>
        </AnimatePresence>
      </div>

      {/* FOOTER ACTION */}
      <footer className="p-4 bg-black/40 border-t border-outline/20 shrink-0">
        <div className="flex items-center justify-between text-[8px] font-mono text-foreground/20">
          <span>{isModule ? 'Global Context' : 'Local Context'}</span>
          <span>SYS_ID: {item.id.slice(0, 8)}</span>
        </div>
      </footer>
    </div>
  );
}

'use client';

import React from 'react';
import yaml from 'js-yaml';
import { Copy, FileCode } from 'lucide-react';

interface SourceViewerProps {
  manifest: Record<string, any>;
}

export default function SourceViewer({ manifest }: SourceViewerProps) {
  const yamlSource = yaml.dump(manifest, { 
    indent: 2, 
    lineWidth: -1, 
    noRefs: true,
    sortKeys: false 
  });

  const copyToClipboard = () => {
    navigator.clipboard.writeText(yamlSource);
  };

  return (
    <div className="h-full flex flex-col bg-[#050505] p-8 overflow-hidden font-mono">
      <div className="max-w-4xl mx-auto w-full flex flex-col h-full space-y-4">
        {/* HEADER */}
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 bg-white/5 border border-white/10 flex items-center justify-center rounded-xs">
                <FileCode className="w-5 h-5 text-foreground/40" />
             </div>
             <div>
                <h2 className="text-[10px] font-black uppercase tracking-[0.3em] text-foreground/80">Manifest Source</h2>
                <p className="text-[8px] text-foreground/20 uppercase tracking-widest">{manifest.id || 'unnamed_module'}.acemm</p>
             </div>
          </div>
          <button 
            onClick={copyToClipboard}
            className="flex items-center gap-2 px-4 py-2 bg-white/5 border border-outline/20 hover:bg-white/10 hover:border-white/40 text-[8px] font-black uppercase tracking-widest text-foreground/60 transition-all rounded-xs group"
          >
            <Copy className="w-3.5 h-3.5 group-hover:scale-110 transition-transform" />
            <span>Copy to Clipboard</span>
          </button>
        </div>

        {/* CODE BLOCK */}
        <div className="flex-1 bg-black/40 border border-outline/10 rounded-sm overflow-hidden flex flex-col shadow-2xl">
          <div className="flex items-center gap-1.5 px-4 py-2 border-b border-outline/5 bg-black/40">
             <div className="w-2 h-2 rounded-full bg-red-500/20" />
             <div className="w-2 h-2 rounded-full bg-amber-500/20" />
             <div className="w-2 h-2 rounded-full bg-green-500/20" />
             <span className="ml-4 text-[7px] font-black text-foreground/20 uppercase tracking-[0.2em]">YAML Serialized Output</span>
          </div>
          <div className="flex-1 overflow-auto p-8 custom-scrollbar">
            <pre className="text-[11px] leading-relaxed text-primary/80">
              {yamlSource}
            </pre>
          </div>
        </div>

        {/* FOOTER HINT */}
        <div className="text-center">
           <p className="text-[7px] text-foreground/20 font-black uppercase tracking-[0.4em]">Aseptic Engineering Standard V7.1</p>
        </div>
      </div>
    </div>
  );
}

'use client';

import { motion, AnimatePresence } from 'framer-motion';
import { useState } from 'react';

interface VirtualRackProps {
  manifest: any;
  selectedItemId: string | null;
  onSelectItem: (id: string) => void;
}

export default function VirtualRack({ manifest, selectedItemId, onSelectItem }: VirtualRackProps) {
  const [activeTab, setActiveTab] = useState('MAIN');

  const controls = manifest?.ui?.controls || [];
  const jacks = manifest?.ui?.jacks || [];
  const allElements = [
    ...controls.map((c: any) => ({ ...c, isJack: false })),
    ...jacks.map((j: any) => ({ ...j, isJack: true }))
  ];

  // Tab counting for visual feedback
  const getTabCount = (tab: string) => {
    return allElements.filter(item => (item.presentation?.tab || 'MAIN') === tab).length;
  };

  // Filter elements by the current active tab
  const visibleElements = allElements.filter(item => (item.presentation?.tab || 'MAIN') === activeTab);

  const rackSettings = manifest?.metadata?.rack || {};
  const skin = manifest?.ui?.skin || 'industrial';
  const isCompact = rackSettings.height_mode === 'compact';
  const hp = rackSettings.hp || 12;
  const displayWidth = hp * 15;
  const displayHeight = isCompact ? 210 : 420;

  const getSkinStyles = () => {
    switch (skin) {
      case 'carbon': return 'bg-[#0a0a0a] border-[#222] shadow-[inset_0_0_100px_rgba(0,0,0,1)]';
      case 'glass': return 'bg-white/5 backdrop-blur-xl border-white/20 shadow-2xl';
      case 'minimal': return 'bg-[#f0f0f0] border-[#ddd] shadow-none text-black';
      case 'industrial':
      default: return 'bg-[#1a1a1a] border-[#333] shadow-[0_40px_80px_rgba(0,0,0,0.8)]';
    }
  };

  const getSizeScale = (variant: string) => {
    const size = variant ? variant.charAt(0) : 'B';
    switch (size) {
      case 'A': return 1.5;
      case 'C': return 0.75;
      case 'D': return 0.5;
      default: return 1.0;
    }
  };

  const getStyleFromVariant = (variant: string) => {
    if (!variant) return 'standard';
    // Handle combined variants like A_cyan, B_red
    if (variant.includes('_')) {
      return variant.split('_')[1];
    }
    // If it's just a size code (A, B, C, D)
    if (['A', 'B', 'C', 'D'].includes(variant)) return 'standard';
    return variant;
  };

  const renderAttachment = (att: any, parentItem: any, scale: number, index: number) => {
    const offset = att.offset || 0;
    const posClasses: Record<string, string> = {
      top: `bottom-full left-1/2 -translate-x-1/2`,
      bottom: `top-full left-1/2 -translate-x-1/2`,
      left: `right-full top-1/2 -translate-y-1/2`,
      right: `left-full top-1/2 -translate-y-1/2`
    };

    const marginStyle: React.CSSProperties = {};
    if (att.position === 'top') marginStyle.marginBottom = `${4 + offset}px`;
    if (att.position === 'bottom') marginStyle.marginTop = `${4 + offset}px`;
    if (att.position === 'left') marginStyle.marginRight = `${8 + offset}px`;
    if (att.position === 'right') marginStyle.marginLeft = `${8 + offset}px`;

    const key = `${parentItem.id}-att-${index}`;

    switch (att.type) {
      case 'led':
        const color = att.role === 'activity' ? '#00f0ff' : att.role === 'gate' ? '#ff8c00' : '#ff4444';
        return (
          <div key={key} className={`absolute ${posClasses[att.position] || ''}`} style={marginStyle}>
            <div style={{ backgroundColor: color, boxShadow: `0 0 5px ${color}` }} className="w-1.5 h-1.5 rounded-full border border-white/20" />
          </div>
        );
      case 'display':
        return (
          <div key={key} className={`absolute ${posClasses[att.position] || ''} bg-black border border-outline px-1 rounded-xs flex flex-col items-center min-w-[20px]`} style={marginStyle}>
            <span className="text-[4px] font-mono text-primary italic leading-tight">88.8</span>
            {att.unit && <span className="text-[3px] text-primary/40 uppercase font-black">{att.unit}</span>}
          </div>
        );
      case 'label':
      default:
        const isMinimal = skin === 'minimal';
        return (
          <div key={key} className={`absolute ${posClasses[att.position] || ''} text-[6px] font-bold uppercase whitespace-nowrap tracking-widest ${isMinimal ? 'text-black/60 bg-black/5' : 'text-white/40 bg-black/40'} px-1 py-0.5 rounded-xs`} style={marginStyle}>
            {att.text || parentItem.label || parentItem.id}
          </div>
        );
    }
  };

  const renderMainComponent = (item: any, scale: number) => {
    const componentType = item.presentation?.component || (item.isJack ? 'port' : 'knob');
    const isSelected = selectedItemId === item.id;
    const variant = item.presentation?.variant || 'B';
    const style = getStyleFromVariant(variant);

    if (componentType === 'hidden') return <div className="w-6 h-6 border-2 border-dashed border-white/5 rounded-full flex items-center justify-center opacity-20"><div className="w-1 h-1 rounded-full bg-white/40" /></div>;

    switch (componentType) {
      case 'led':
        const ledColor = style === 'red' ? '#ff4444' : style === 'green' ? '#00ff88' : style === 'yellow' ? '#ffcc00' : '#00f0ff';
        const ledSize = (variant.startsWith('A') ? 20 : 12) * scale;
        return (
          <div style={{ width: `${ledSize}px`, height: `${ledSize}px`, backgroundColor: ledColor, boxShadow: `0 0 ${15 * scale}px ${ledColor}66` }} className="rounded-full border border-white/30" />
        );
      case 'display':
        return (
          <div style={{ width: `${80 * scale}px`, height: `${28 * scale}px` }} className="bg-black border-2 border-outline/40 rounded-sm flex items-center overflow-hidden shadow-[0_0_15px_rgba(0,240,255,0.1)]">
            <div className="flex-1 h-full flex flex-col items-center justify-center border-r border-outline/20 bg-primary/5">
              <span className="text-[9px] font-mono text-primary font-bold animate-pulse">000</span>
            </div>
            <div className="w-6 h-full flex flex-col">
              <div className="flex-1 bg-white/5 border-b border-outline/20 flex items-center justify-center text-[8px] text-primary/60 hover:text-primary transition-colors">+</div>
              <div className="flex-1 bg-white/5 flex items-center justify-center text-[8px] text-primary/60 hover:text-primary transition-colors">-</div>
            </div>
          </div>
        );
      case 'select':
        return (
          <div style={{ width: `${64 * scale}px`, height: `${20 * scale}px` }} className="bg-black border border-outline rounded-xs flex items-center justify-between px-2">
            <span className="text-[7px] font-mono text-primary truncate max-w-[80%] uppercase tracking-tighter">{item.label || 'SELECT'}</span>
            <div className="w-0 h-0 border-l-[3px] border-l-transparent border-r-[3px] border-r-transparent border-t-[4px] border-t-primary/60" />
          </div>
        );
      case 'slider-v':
        return (
          <div style={{ width: `${20 * scale}px`, height: `${60 * scale}px` }} className="bg-black/40 border border-outline rounded-full flex flex-col items-center p-1">
            <div className="w-full h-1/2 bg-primary/20 rounded-full" />
            <div className="w-4 h-2 bg-primary rounded-xs shadow-[0_0_10px_rgba(0,240,255,0.4)]" />
          </div>
        );
      case 'slider-h':
        return (
          <div style={{ width: `${60 * scale}px`, height: `${20 * scale}px` }} className="bg-black/40 border border-outline rounded-full flex items-center p-1">
            <div className="h-full w-1/2 bg-primary/20 rounded-full" />
            <div className="h-4 w-2 bg-primary rounded-xs shadow-[0_0_10px_rgba(0,240,255,0.4)]" />
          </div>
        );
      case 'port':
        const isGold = style === 'gold';
        return (
          <div style={{ width: `${24 * scale}px`, height: `${24 * scale}px` }} className={`rounded-full border-2 bg-[#000] flex items-center justify-center ${isSelected ? (isGold ? 'border-yellow-500 shadow-[0_0_10px_rgba(255,200,0,0.3)]' : 'border-accent shadow-[0_0_10px_rgba(255,140,0,0.2)]') : (isGold ? 'border-yellow-600/60' : 'border-[#444]')}`}>
            <div className={`w-[60%] h-[60%] rounded-full bg-[#111] border ${isGold ? 'border-yellow-500/20' : 'border-white/5'} shadow-inner`} />
          </div>
        );
      case 'knob':
      default:
        const diameter = 32 * scale;
        const knobPointer = style === 'blue' ? '#00f0ff' : style === 'vintage' ? '#ffcc00' : '#00f0ffaa';
        return (
          <div style={{ width: `${diameter}px`, height: `${diameter}px` }} className={`rounded-full border-2 border-[#333] bg-[#111] flex items-center justify-center relative ${isSelected ? 'border-primary shadow-[0_0_15px_rgba(0,240,255,0.2)]' : ''}`}>
            <div style={{ height: '35%', backgroundColor: knobPointer }} className="w-[2px] rounded-full mb-[60%]" />
            <div className="absolute inset-0 rounded-full bg-gradient-to-tr from-white/5 to-transparent pointer-events-none" />
          </div>
        );
    }
  };

  return (
    <div className="w-full h-full flex flex-col items-center justify-center bg-black/40 gap-8 p-12 relative overflow-hidden">
      {/* RACK TAB SELECTOR WITH COUNTERS */}
      <div className="flex gap-1 bg-black/60 p-1 rounded-full border border-white/10 z-20 shadow-2xl">
        {['MAIN', 'PATCHING', 'SETUP', 'MIDI'].map(t => {
          const count = getTabCount(t);
          return (
            <button 
              key={t} 
              onClick={() => setActiveTab(t)}
              className={`px-4 py-1.5 rounded-full text-[9px] font-black tracking-widest transition-all flex items-center gap-2 ${activeTab === t ? 'bg-primary text-background' : 'text-white/40 hover:text-white'}`}
            >
              <span>{t}</span>
              {count > 0 && <span className={`px-1.5 rounded-full text-[7px] ${activeTab === t ? 'bg-background text-primary' : 'bg-white/10 text-white/40'}`}>{count}</span>}
            </button>
          );
        })}
      </div>

      <div className={`relative border-x-[3px] border-y-[1px] transition-all duration-700 ${getSkinStyles()}`} 
           style={{ width: `${displayWidth * 1.5}px`, height: `${displayHeight * 1.5}px` }}>

        {/* BRANDING */}
        <div className="absolute top-8 left-0 right-0 text-center pointer-events-none">
          <div className="text-[8px] font-headline font-bold italic opacity-10 tracking-tighter uppercase">ABD OMEGA ERA 7</div>
          <div className="text-[7px] text-primary/20 tracking-[0.3em] uppercase font-bold mt-1">{manifest?.metadata?.name || manifest?.name || 'ASEPTIC MODULE'}</div>
        </div>

        {/* ELEMENTS */}
        <AnimatePresence mode="popLayout">
          {visibleElements.map((item: any) => {
            const variant = item.presentation?.variant || 'B';
            const scale = getSizeScale(variant);
            return (
              <motion.div
                key={item.id}
                layoutId={item.id}
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.8 }}
                onClick={() => onSelectItem(item.id)}
                style={{ left: `${item.pos?.x * 1.5}px`, top: `${item.pos?.y * 1.5}px` }}
                className={`absolute transform -translate-x-1/2 -translate-y-1/2 cursor-pointer ${selectedItemId === item.id ? 'z-50' : 'z-10'}`}
              >
                <div className="relative flex items-center justify-center">
                   {(item.presentation?.attachments || []).map((att: any, idx: number) => renderAttachment(att, item, scale, idx))}
                   <div className={`transition-all duration-300 ${selectedItemId === item.id ? 'scale-110' : ''}`}>
                     {renderMainComponent(item, scale)}
                   </div>
                </div>
              </motion.div>
            );
          })}
        </AnimatePresence>

        {skin === 'carbon' && <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: 'linear-gradient(45deg, #000 25%, transparent 25%, transparent 50%, #000 50%, #000 75%, transparent 75%, transparent)', backgroundSize: '4px 4px' }} />}
      </div>

      <div className="text-[8px] text-white/20 uppercase font-black tracking-widest mt-4">
        {skin} Skin active • {activeTab} View ({visibleElements.length} elements)
      </div>
    </div>
  );
}

'use client';

import { useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Header from './Header';
import ModuleHub from './ModuleHub';
import ControlRegistry from './ControlRegistry';
import VirtualRack from './VirtualRack';
import NodeCanvas from './NodeCanvas';
import PropertyPanel from './PropertyPanel';
import LogTerminal from './LogTerminal';
import SourceViewer from './SourceViewer';
import { useManifestEditor } from '@/hooks/useManifestEditor';

/**
 * WorkbenchContainer
 * Pure Orchestrator for the OMEGA Manifest Engineering Suite.
 * Handles layout routing, visibility state, and component mapping.
 */
export default function WorkbenchContainer() {
  const { 
    manifest, 
    contract, 
    updateManifest,
    findItem,
    updateItem,
    removeItem,
    duplicateItem,
    addEntity, 
    exportManifest, 
    handleManifestUpload,
    handleWasmUpload,
    handleContractUpload,
    reset,
    logs
  } = useManifestEditor();

  // Navigation & Selection State
  const [viewMode, setViewMode] = useState<'orbital' | 'rack' | 'source'>('orbital');
  const [selectedItemId, setSelectedItemId] = useState<string | null>(null);
  const [showLogs, setShowLogs] = useState(false);

  // Event Handlers (Orchestration)
  const triggerUpload = (id: string) => document.getElementById(id)?.click();

  const handleSelectItem = useCallback((id: string) => {
    setSelectedItemId(id);
  }, []);

  const handleAddEntity = useCallback((type: 'control' | 'jack') => {
    const id = addEntity(type);
    if (id) handleSelectItem(id);
  }, [addEntity, handleSelectItem]);

  const handleDuplicateItem = useCallback((id: string) => {
    const newId = duplicateItem(id);
    if (newId) handleSelectItem(newId);
  }, [duplicateItem, handleSelectItem]);

  // Derived Data\n  const availableBinds = contract ? [\n    ...(contract.parameters?.map((p: { id: string }) => p.id) || []),\n    ...(contract.ports?.map((p: { id: string }) => p.id) || [])\n  ] : [];\n
  const selectedItem = selectedItemId ? findItem(selectedItemId) : manifest;

  return (
    <div className="h-screen flex flex-col bg-[#050505] text-foreground font-sans overflow-hidden relative">
      {/* HIDDEN FILE INPUTS */}
      <input id="manifest-upload" type="file" accept=".json,.acemm" className="hidden" onChange={(e) => e.target.files?.[0] && handleManifestUpload(e.target.files[0])} />
      <input id="wasm-upload" type="file" accept=".wasm" className="hidden" onChange={(e) => e.target.files?.[0] && handleWasmUpload(e.target.files[0])} />
      <input id="contract-upload" type="file" accept=".json" className="hidden" onChange={(e) => e.target.files?.[0] && handleContractUpload(e.target.files[0])} />

      <Header 
        onReset={reset}
        onExport={exportManifest}
        onToggleLogs={() => setShowLogs(!showLogs)}
        showLogs={showLogs}
        viewMode={viewMode}
        setViewMode={setViewMode}
      />

      <main className="flex-1 flex overflow-hidden">
        {/* LEFT SIDEBAR: HUB & REGISTRY */}
        <aside className="w-80 border-r border-outline bg-black/40 flex flex-col min-w-[320px]">
          <div className="flex-1 overflow-y-auto custom-scrollbar p-6 space-y-8">
            <ModuleHub 
              manifest={manifest} 
              contract={contract} 
              triggerUpload={triggerUpload} 
            />

            <ControlRegistry 
              manifest={manifest}
              selectedItemId={selectedItemId}
              onSelectItem={handleSelectItem}
              onAddEntity={handleAddEntity}
              onDuplicateItem={handleDuplicateItem}
              onRemoveItem={removeItem}
            />
          </div>
        </aside>

        {/* CENTER VIEWPORT */}
        <section className="flex-1 relative bg-black overflow-hidden">
          <AnimatePresence mode="wait">
            {viewMode === 'orbital' ? (
              <motion.div 
                key="orbital"
                initial={{ opacity: 0, scale: 0.98 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 1.02 }}
                className="h-full"
              >
                <NodeCanvas 
                  manifest={manifest}
                  contract={contract}
                  selectedItemId={selectedItemId}
                  onSelectItem={handleSelectItem}
                  onUpdateItem={updateItem}
                />
              </motion.div>
            ) : viewMode === 'rack' ? (
              <motion.div 
                key="rack"
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -20 }}
                className="h-full"
              >
                <VirtualRack 
                  manifest={manifest}
                  onSelectItem={handleSelectItem}
                  selectedItemId={selectedItemId}
                />
              </motion.div>
            ) : (
              <motion.div 
                key="source"
                initial={{ opacity: 0, scale: 1.05 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                className="h-full"
              >
                <SourceViewer manifest={manifest} />
              </motion.div>
            )}
          </AnimatePresence>
        </section>

        {/* RIGHT SIDEBAR: INSPECTOR */}
        <AnimatePresence>
          <motion.aside 
            key="inspector"
            initial={{ x: 400 }}
            animate={{ x: 0 }}
            exit={{ x: 400 }}
            className="w-[400px] shrink-0 h-full border-l border-outline/20"
          >
            <PropertyPanel 
              item={selectedItem}
              onUpdate={selectedItemId ? (updates: any) => updateItem(selectedItemId, updates) : updateManifest}
              onClose={() => setSelectedItemId(null)}
              availableBinds={availableBinds}
              scale={1}
            />
          </motion.aside>
        </AnimatePresence>
      </main>

      {/* FLOATING LOG TERMINAL */}
      <AnimatePresence>
        {showLogs && (
          <motion.div 
            initial={{ y: '100%' }}
            animate={{ y: 0 }}
            exit={{ y: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="absolute bottom-0 left-0 right-0 h-80 z-[100] shadow-[0_-10px_40px_rgba(0,0,0,0.8)]"
          >
            <div className="h-full border-t border-accent/30">
               <LogTerminal logs={logs} />
               <button 
                 onClick={() => setShowLogs(false)}
                 className="absolute top-2 right-4 p-1 text-foreground/20 hover:text-foreground/60 transition-colors"
               >
                 <span className="text-[9px] font-black uppercase tracking-widest">Close</span>
               </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

'use client';

import React from 'react';
import { Palette, Box, AlertCircle } from 'lucide-react';
import KnobProperties from './KnobProperties';
import LedProperties from './LedProperties';
import PortProperties from './PortProperties';
import SliderProperties from './SliderProperties';
import DisplayProperties from './DisplayProperties';
import SwitchProperties from './SwitchProperties';
import SelectProperties from './SelectProperties';

interface AestheticSectionProps {\n  item: {\n    presentation?: {\n      component?: string;\n      [key: string]: any;\n    };\n    [key: string]: any;\n  };\n  onUpdate: (updates: any) => void;\n}\n\nexport default function AestheticSection({ item, onUpdate }: AestheticSectionProps) {\n  const componentType = item.presentation?.component || 'knob';\n\n  const renderSpecializedEditor = () => {\n    switch (componentType) {\n      case 'knob':\n        return <KnobProperties item={item} onUpdate={onUpdate} />;\n      case 'led':\n        return <LedProperties item={item} onUpdate={onUpdate} />;\n      case 'port':\n        return <PortProperties item={item} onUpdate={onUpdate} />;\n      case 'slider-v':\n      case 'slider-h':\n        return <SliderProperties item={item} onUpdate={onUpdate} />;\n      case 'display':\n        return <DisplayProperties item={item} onUpdate={onUpdate} />;\n      case 'select':\n        return <SelectProperties item={item} onUpdate={onUpdate} />;\n      case 'switch':\n      case 'button':\n        return <SwitchProperties item={item} onUpdate={onUpdate} />;\n      default:\n        return (\n          <div className=\"p-8 border border-dashed border-outline/10 rounded-xs flex flex-col items-center justify-center gap-3 opacity-30\">\n            <Box className=\"w-8 h-8\" />\n            <div className=\"text-center\">\n              <p className=\"text-[10px] font-black uppercase tracking-widest\">Generic Component</p>\n              <p className=\"text-[7px] font-bold mt-1 italic uppercase\">No specialized aesthetics for &apos;{componentType}&apos;</p>\n            </div>\n          </div>\n        );\n    }\n  };\n
  return (
    <div className="space-y-6">
      {/* SECTION HEADER */}
      <div className="flex items-center justify-between pb-2 border-b border-outline/10">
        <div className="flex items-center gap-2">
          <Palette className="w-3.5 h-3.5 text-primary" />
          <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-foreground/80">Aesthetic Engineering</h3>
        </div>
        <div className="px-2 py-0.5 bg-primary/10 border border-primary/20 rounded-full">
           <span className="text-[7px] font-black text-primary uppercase tracking-tighter">{componentType}</span>
        </div>
      </div>

      {/* DYNAMIC SPECIALIZED EDITOR */}
      <div className="min-h-[200px]">
        {renderSpecializedEditor()}
      </div>

      {/* SYSTEM NOTES */}
      <div className="p-4 bg-black/40 border border-outline/10 rounded-xs space-y-2 border-l-2 border-l-primary/40 mt-10">
         <div className="flex items-center gap-2 text-[7px] font-black text-foreground/20 uppercase tracking-widest">
