'use client';

import React from 'react';
import { Plus, X, Type, Tag, Activity, Link2, Hash } from 'lucide-react';

interface AttachmentsSectionProps {
  item: any;
  onUpdate: (updates: any) => void;
  availableBinds?: string[];
}

export default function AttachmentsSection({ item, onUpdate, availableBinds = [] }: AttachmentsSectionProps) {
  const attachments = item.presentation?.attachments || [];

  const addAttachment = () => {
    const newAtt = { type: 'label', position: 'bottom', offset: 0, role: 'standard' };
    onUpdate({ presentation: { ...item.presentation, attachments: [...attachments, newAtt] } });
  };

  const removeAttachment = (idx: number) => {
    onUpdate({ presentation: { ...item.presentation, attachments: attachments.filter((_: any, i: number) => i !== idx) } });
  };

  const updateAttachment = (idx: number, updates: any) => {
    const newAtts = [...attachments];
    newAtts[idx] = { ...newAtts[idx], ...updates };
    onUpdate({ presentation: { ...item.presentation, attachments: newAtts } });
  };

  const updateFormat = (idx: number, formatUpdates: any) => {
    const att = attachments[idx];
    const newFormat = { ...(att.format || {}), ...formatUpdates };
    updateAttachment(idx, { format: newFormat });
  };

  return (
    <div className="space-y-4 pt-2">
      <div className="flex justify-between items-center bg-white/5 p-2 rounded-xs border border-outline/10">
        <span className="text-[8px] font-black text-foreground/40 uppercase tracking-widest">Active Attachments</span>
        <button 
          onClick={addAttachment}
          className="p-1 bg-primary text-background hover:scale-110 transition-transform rounded-xs"
        >
          <Plus className="w-3 h-3" />
        </button>
      </div>

      <div className="space-y-4 max-h-[500px] overflow-y-auto pr-1 custom-scrollbar">
        {attachments.map((att: any, idx: number) => (
          <div key={idx} className="p-3 bg-black/40 border border-outline/20 rounded-sm space-y-4 relative group shadow-lg">
            <button 
              onClick={() => removeAttachment(idx)} 
              className="absolute top-2 right-2 text-foreground/20 hover:text-red-500 transition-colors"
            >
              <X className="w-3.5 h-3.5" />
            </button>

            {/* TYPE & POSITION */}
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1">
                <label className="text-[7px] text-foreground/40 uppercase font-bold flex items-center gap-1">
                  <Activity className="w-2 h-2" />
                  <span>Type</span>
                </label>
                <select 
                  value={att.type} 
                  onChange={(e) => updateAttachment(idx, { type: e.target.value })}
                  className="w-full bg-black/60 border border-outline rounded-xs p-1.5 text-[9px] text-primary outline-none"
                >
                  <option value="label">Label</option>
                  <option value="display">Display</option>
                  <option value="led">LED</option>
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-[7px] text-foreground/40 uppercase font-bold">Position</label>
                <select 
                  value={att.position} 
                  onChange={(e) => updateAttachment(idx, { position: e.target.value })}
                  className="w-full bg-black/60 border border-outline rounded-xs p-1.5 text-[9px] text-foreground outline-none"
                >
                  <option value="top">Top</option>
                  <option value="bottom">Bottom</option>
                  <option value="left">Left</option>
                  <option value="right">Right</option>
                </select>
              </div>
            </div>

            {/* BINDING (New Era 6 feature in Era 7) */}
            <div className="space-y-1">
              <label className="text-[7px] text-foreground/40 uppercase font-bold flex items-center gap-1">
                <Link2 className="w-2 h-2" />
                <span>Dynamic Signal Bind (Source)</span>
              </label>
              <select 
                value={att.bind || ''} 
                onChange={(e) => updateAttachment(idx, { bind: e.target.value })}
                className="w-full bg-black/60 border border-outline rounded-xs p-1.5 text-[9px] text-accent outline-none font-mono"
              >
                <option value="">-- AUTO (Binds to Parent) --</option>
                {availableBinds.map(b => (
                  <option key={b} value={b}>{b}</option>
                ))}
              </select>
            </div>

            {/* ROLE & TEXT */}
            <div className="grid grid-cols-2 gap-3">
              <div className="space-y-1">
                <label className="text-[7px] text-foreground/40 uppercase font-bold flex items-center gap-1">
                  <Tag className="w-2 h-2" />
                  <span>Role</span>
                </label>
                <select 
                  value={att.role || 'standard'} 
                  onChange={(e) => updateAttachment(idx, { role: e.target.value })}
                  className="w-full bg-black/60 border border-outline rounded-xs p-1.5 text-[9px] text-foreground outline-none"
                >
                  <option value="standard">Standard</option>
                  <option value="value">Live Value</option>
                  <option value="unit">Unit Marker</option>
                  <option value="status">Status</option>
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-[7px] text-foreground/40 uppercase font-bold flex items-center gap-1">
                  <Type className="w-2 h-2" />
                  <span>Static Text</span>
                </label>
                <input 
                  type="text" 
                  value={att.text || ''} 
                  onChange={(e) => updateAttachment(idx, { text: e.target.value })}
                  placeholder="Override text..."
                  className="w-full bg-black/60 border border-outline rounded-xs p-1.5 text-[9px] text-foreground outline-none"
                />
              </div>
            </div>

            {/* FORMATTING BLOCK (New Era 6 feature in Era 7) */}
            <div className="p-2 border border-outline/10 bg-white/5 rounded-xs space-y-3">
               <div className="text-[7px] font-black text-foreground/20 uppercase tracking-tighter flex items-center gap-1">
                  <Hash className="w-2 h-2" />
                  <span>Value Formatting</span>
               </div>
               <div className="grid grid-cols-3 gap-2">
                  <div className="space-y-1">
                    <label className="text-[6px] text-foreground/40 uppercase font-bold text-center block">Prefix</label>
                    <input 
                      type="text" 
                      value={att.format?.prefix || ''} 
                      onChange={(e) => updateFormat(idx, { prefix: e.target.value })}
                      className="w-full bg-black/60 border border-outline rounded-xs p-1 text-[8px] text-foreground outline-none"
                      placeholder="e.g. Vol:"
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[6px] text-foreground/40 uppercase font-bold text-center block">Suffix</label>
                    <input 
                      type="text" 
                      value={att.format?.suffix || ''} 
                      onChange={(e) => updateFormat(idx, { suffix: e.target.value })}
                      className="w-full bg-black/60 border border-outline rounded-xs p-1 text-[8px] text-foreground outline-none"
                      placeholder="e.g. Hz"
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[6px] text-foreground/40 uppercase font-bold text-center block">Decimals</label>
                    <input 
                      type="number" 
                      value={att.format?.decimals ?? 2} 
                      onChange={(e) => updateFormat(idx, { decimals: parseInt(e.target.value) })}
                      className="w-full bg-black/60 border border-outline rounded-xs p-1 text-[8px] text-primary outline-none font-mono"
                    />
                  </div>
               </div>
            </div>

            {/* OFFSET SLIDER */}
            <div className="space-y-1">
              <div className="flex justify-between items-center">
                <label className="text-[7px] text-foreground/40 uppercase font-bold tracking-widest">Vertical Offset</label>
                <span className="text-[8px] text-primary font-mono font-bold bg-primary/5 px-1 rounded-xs">{att.offset || 0}px</span>
              </div>
              <input 
                type="range" 
                min="-40" 
                max="40" 
                value={att.offset || 0} 
                onChange={(e) => updateAttachment(idx, { offset: parseInt(e.target.value) })}
                className="w-full accent-primary/40 h-1 bg-black/60 rounded-full appearance-none cursor-pointer"
              />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

'use client';

import React from 'react';
import { motion } from 'framer-motion';

interface CellPreviewProps {
  item: any;
}

export default function CellPreview({ item }: CellPreviewProps) {
  const componentType = item.presentation?.component || 'knob';
  const attachments = item.presentation?.attachments || [];

  const renderCore = () => {
    switch (componentType) {
      case 'knob':
        return (
          <div className="relative w-16 h-16 flex items-center justify-center">
            <div className="absolute inset-0 rounded-full border-2 border-primary/20 bg-black/40 shadow-[0_0_20px_rgba(0,240,255,0.1)]" />
            <div className="w-12 h-12 rounded-full bg-gradient-to-br from-white/10 to-transparent border border-white/10 shadow-lg relative">
               <div className="absolute top-1 left-1/2 -translate-x-1/2 w-1 h-3 bg-primary rounded-full shadow-[0_0_8px_rgba(0,240,255,0.8)]" />
            </div>
          </div>
        );
      case 'port':
      case 'jack':
        return (
          <div className="w-14 h-14 rounded-full border-4 border-outline/30 bg-black flex items-center justify-center shadow-inner relative">
             <div className="w-8 h-8 rounded-full border-2 border-outline/10 bg-white/5 flex items-center justify-center">
                <div className="w-4 h-4 rounded-full bg-black border border-white/20" />
             </div>
          </div>
        );
      case 'slider-v':
        return (
          <div className="w-8 h-24 bg-black/60 border border-outline/20 rounded-sm relative flex flex-col items-center p-1">
             <div className="w-px h-full bg-white/10 absolute left-1/2 -translate-x-1/2" />
             <div className="w-6 h-10 bg-primary/20 border border-primary/40 rounded-xs z-10 mt-6 shadow-[0_0_10px_rgba(0,240,255,0.2)] flex items-center justify-center">
                <div className="w-4 h-0.5 bg-primary/60" />
             </div>
          </div>
        );
      case 'led':
        return (
          <div className="w-6 h-6 rounded-full bg-primary/20 border-2 border-primary/40 shadow-[0_0_15px_rgba(0,240,255,0.3)]" />
        );
      case 'display':
        return (
          <div className="w-24 h-10 bg-black/80 border border-outline/30 rounded-xs flex items-center justify-center font-mono text-primary text-[10px] shadow-[inset_0_0_10px_rgba(0,0,0,1)]">
             <span className="opacity-80">--.---</span>
          </div>
        );
      default:
        return <div className="w-12 h-12 border-2 border-dashed border-outline/20 rounded-full" />;
    }
  };

  const renderAttachment = (att: any) => {
    const offsetStyle = {
      marginTop: att.position === 'bottom' ? `${6 + (att.offset || 0)}px` : 0,
      marginBottom: att.position === 'top' ? `${6 + (att.offset || 0)}px` : 0,
      marginLeft: att.position === 'right' ? `${6 + (att.offset || 0)}px` : 0,
      marginRight: att.position === 'left' ? `${6 + (att.offset || 0)}px` : 0,
    };

    return (
      <motion.div
        initial={{ scale: 0, opacity: 0 }}
        animate={{ scale: 1, opacity: 1 }}
        style={offsetStyle}
        className="flex items-center justify-center whitespace-nowrap z-10"
      >
        {att.type === 'label' && (
          <span className="text-[9px] font-black uppercase tracking-[0.2em] text-foreground/80 bg-black/80 px-2 py-1 rounded-xs border border-outline/20 backdrop-blur-md shadow-2xl">
            {att.text || item.label || 'LABEL'}
          </span>
        )}
        {att.type === 'led' && (
          <div className="w-2 h-2 rounded-full bg-accent shadow-[0_0_10px_rgba(240,0,255,0.8)] border border-white/20" />
        )}
        {att.type === 'display' && (
          <div className="px-2 py-1 bg-black border border-outline/40 rounded-xs shadow-2xl flex items-center gap-1.5 min-w-[40px] justify-center">
             <span className="text-[8px] font-mono text-primary font-bold">0.00</span>
             {att.unit && <span className="text-[6px] text-foreground/40 font-black uppercase">{att.unit}</span>}
          </div>
        )}
      </motion.div>
    );
  };

  const topAtts = attachments.filter((a: any) => a.position === 'top');
  const bottomAtts = attachments.filter((a: any) => a.position === 'bottom');
  const leftAtts = attachments.filter((a: any) => a.position === 'left');
  const rightAtts = attachments.filter((a: any) => a.position === 'right');

  return (
    <div className="w-full bg-[#080808] border-b border-outline/20 p-8 flex items-center justify-center relative overflow-hidden h-60 bg-[radial-gradient(circle_at_50%_50%,rgba(0,240,255,0.05),transparent)]">
      {/* GRID BACKGROUND */}
      <div className="absolute inset-0 opacity-10 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at 1px 1px, #ffffff 1px, transparent 0)', backgroundSize: '16px 16px' }} />

      {/* CANONICAL FLEX CONTAINER (Mirroring the Rack's Column Layout) */}
      <div className="flex flex-col items-center justify-center relative min-w-[120px]">

        {/* TOP STACK */}
        <div className="flex flex-col items-center justify-end">
           {topAtts.map((att: any, i: number) => <div key={i}>{renderAttachment(att)}</div>)}
        </div>

        {/* MIDDLE ROW (Component + Lateral Attachments) */}
        <div className="flex items-center justify-center relative">
          {/* LEFT STACK */}
          <div className="flex items-center justify-end">
             {leftAtts.map((att: any, i: number) => <div key={i}>{renderAttachment(att)}</div>)}
          </div>

          {/* CORE */}
          <motion.div 
            key={componentType}
            initial={{ scale: 0.8, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            className="shrink-0 z-0"
          >
            {renderCore()}
          </motion.div>

          {/* RIGHT STACK */}
          <div className="flex items-center justify-start">
             {rightAtts.map((att: any, i: number) => <div key={i}>{renderAttachment(att)}</div>)}
          </div>
        </div>

        {/* BOTTOM STACK */}
        <div className="flex flex-col items-center justify-start">
           {bottomAtts.map((att: any, i: number) => <div key={i}>{renderAttachment(att)}</div>)}
        </div>
      </div>

      {/* RULER INFO */}
      <div className="absolute bottom-3 left-4 flex items-center gap-3 opacity-20">
         <div className="h-[1px] w-12 bg-primary/40" />
         <span className="text-[7px] font-black uppercase tracking-[0.4em] text-primary italic">Canonical Flex Preview</span>
      </div>
    </div>
  );
}

