                <span className={`text-[9px] font-black uppercase tracking-widest ${currentVariant === m.id ? 'text-primary' : 'text-foreground/60'}`}>
                  {m.label}
                </span>
                <span className="text-[8px] font-mono opacity-20 group-hover:opacity-100 transition-opacity">.{m.id}</span>
              </div>
              <p className="text-[7px] text-foreground/30 italic uppercase">{m.desc}</p>
              {currentVariant === m.id && <div className="absolute left-0 top-0 bottom-0 w-1 bg-primary" />}
            </button>
          ))}
        </div>
      </div>

      <div className="p-4 bg-primary/5 border border-primary/10 rounded-xs space-y-2">
         <div className="flex items-center gap-2 text-[7px] font-black text-primary/40 uppercase tracking-widest">
            <Palette className="w-3 h-3" />
            <span>Signal Indication</span>
         </div>
         <p className="text-[8px] text-foreground/40 leading-relaxed italic">
            Port identification rings are automatically generated by the theme based on the <b>Signal Role</b> defined in Engineering.
         </p>
      </div>
    </div>
